text:
Aggregate Community Health
This page shows aggregate community health scores for all repositories within the mrcieu.r-universe.dev organization. Higher values describe repositories with greater community health scores. Values for individual models are standardised across all repositories to have mean values of zero and standard deviations of one. These results are aggregated across thirteen distinct models, leading to maximal aggregated values slightly exceeding that value.

Plot = import("https://esm.sh/@observablehq/plot")







models_all = {
    return transpose(models_in).map(row =&gt; ({
        ...row,
    }));
}
models_final = models_all.filter(function(mod) {
    return mod.name === "final"
})
models_len = models_final.length























Plot.plot({
    height: 20 * models_len,
    marginLeft: 60,
    marginRight: 160,
    marginTop: 50,
    marginBottom: 50,
    axis: null,
    x: {
        axis: "top",
        grid: true,
        label: "Community Health"
    },
    y: { grid: true },
    marks: [
        Plot.barX(models_final, {
            y: "package",
            x: "value",
            sort: {y: "-x" },
            fill: "value",
        }),
        Plot.barX(models_final,
            Plot.pointer(
            {
                y: "package",
                x: "value",
                sort: {y: "-x" },
                stroke: "gray",
                fill: "value",
                strokeWidth: 2,
            })
        ),
        Plot.text(models_final, {
            x: (d) =&gt; d.value &lt; 0 ? 0 : d.value,
            y: "package",
            text: "package",
            textAnchor: "start",
            fontSize: 16,
            dx: 5
        })
    ],
    color: {
        scheme: "Cool",
        type: "ordinal"
    }
})

Individual models of community health
The following section shows values for each individual model of community health for all repositories.

json_data = FileAttachment("results-json-data.json").json();
rm_metrics_models = json_data['rm_metrics_models'];
rm_models = rm_metrics_models['models'];
rm_model_text = rm_metrics_models['model_names'];
modelsTextMap = rm_model_text.reduce((map, item) =&gt; {
    return map.set(String(item.name), item.airtable_name);
}, new Map());
modelsUrlMap = rm_model_text.reduce((map, item) =&gt; {
    return map.set(String(item.name), item.url);
}, new Map());












































commHealthVars = Array.from(modelsTextMap.keys());
commHealthText = commHealthVars.map(item =&gt; {
    return modelsTextMap.has(item) ? modelsTextMap.get(item) : "";
})
viewof commHealthVar = Inputs.select(
    rm_model_text,
    {
        multiple: "false",
        label: "Community Health Variable",
        format: x =&gt; x.airtable_name,
    }
);

htl.html`&lt;div&gt;
Click this link for description of the &lt;a href="${commHealthVar.url}" target="_blank"&gt;
&lt;i&gt;${commHealthVar.airtable_name}&lt;/i&gt;&lt;/a&gt; CHAOSS model.
&lt;/div&gt;`






























models_filtered = models_all.filter(function(mod) {
    return mod.name === commHealthVar.name
})







Plot.plot({
    height: 20 * models_len,
    marginLeft: 60,
    marginRight: 160,
    marginTop: 50,
    marginBottom: 50,
    axis: null,
    x: {
        axis: "top",
        grid: true,
        label: "Community Health"
    },
    y: { grid: true },
    marks: [
        Plot.barX(models_filtered, {
            y: "package",
            x: "value",
            sort: {y: "-x" },
            fill: "value",
        }),
        Plot.barX(models_filtered,
            Plot.pointer(
            {
                y: "package",
                x: "value",
                sort: {y: "-x" },
                stroke: "gray",
                fill: "value",
                strokeWidth: 2,
            })
        ),
        Plot.text(models_filtered, {
            x: (d) =&gt; d.value &lt; 0 ? 0 : d.value,
            y: "package",
            text: "package",
            textAnchor: "start",
            fontSize: 16,
            dx: 5
        })
    ],
    color: {
        scheme: "Cool",
        type: "ordinal"
    }
})

Community health for individual repositories
The following section shows all models of community health for a selected repository. The names of the models are hyperlinked to the definitions within the specific pages of the CHAOSS models.

reposAll = models_all.map(function(item) {
    return item.package;
});
repos = Array.from(new Set(reposAll)).sort((a, b) =&gt;
    a.localeCompare(b, undefined, { sensitivity: 'base' })
);
repoSet = localStorage.getItem("orgmetricsRepo") || repos [0]
viewof repo = Inputs.select(
    repos,
    {
        multiple: false,
        value: repoSet,
        label: htl.html`&lt;b&gt;Repository:&lt;/b&gt;`
    }
)
tmpval = localStorage.setItem("orgmetricsRepo", repo.toString());





































models_with_url = models_all.map(item =&gt; {
    const key = item.name;
    const url = modelsUrlMap.has(key) ? modelsUrlMap.get(key) :
        "https://chaoss.community/kbtopic/all-metrics-models/";
    const fullname = modelsTextMap.has(key) ? modelsTextMap.get(key) : item.name
    return {
        ...item,
        fullname: fullname,
        url: url
    }
})
model_repo = models_with_url.filter(function(mod) {
    return mod.package === repo && mod.name !== "final"
})
model_repo_len = model_repo.length
bar_ht_mult = model_repo_len &gt; 20 ? 20 : 40;






























Plot.plot({
    height: bar_ht_mult * model_repo_len,
    marginLeft: 60,
    marginRight: 160,
    marginTop: 50,
    marginBottom: 50,
    axis: null,
    x: {
        axis: "top",
        grid: true,
        label: "Community Health"
    },
    y: { grid: true },
    marks: [
        Plot.barX(model_repo, {
            y: d =&gt; d.fullname,
            x: d =&gt; d.value,
            sort: {y: "-x" },
            fill: d =&gt; d.value,
        }),
        Plot.barX(model_repo,
            Plot.pointer(
            {
                y: d =&gt; d.fullname,
                x: d =&gt; d.value,
                sort: {y: "-x" },
                stroke: "gray",
                fill: d =&gt; d.value,
                strokeWidth: 2,
            })
        ),
        Plot.text(model_repo, {
            x: d =&gt; d.value,
            y: d =&gt; d.fullname,
            text: d =&gt; d.fullname,
            href: d =&gt; d.url,
            textAnchor: "start",
            fontSize: 16,
            dx: 5
        })
    ],
    color: {
        scheme: "Cool",
        type: "ordinal"
    }
})

function sparkbar(max) {
  const colourScale = d3.scaleSequential(d3.interpolateCool)
    .domain([0, max]);

  return (x) =&gt; htl.html`&lt;div style="
    background: ${colourScale(x)};
    color: black;
    width: ${100 * x / max}%;
    float: right;
    padding-right: 3px;
    box-sizing: border-box;
    overflow: visible;
    display: flex;
    justify-content: end;"&gt;${x.toFixed(2).toLocaleString("en-US")}`
}

function tooltip(title, expl) {
    const th = document.createElement("th");
    th.title = expl
    th.style.background = "#f0f8ff";
    th.textContent = title;

    th.addEventListener("mouseover", () =&gt; th.style.background = "#d0e8ff");
    th.addEventListener("mouseout", () =&gt; th.style.background = "#f0f8ff");

    return th;
}

function pkgfmt(pkg) {
    const th = document.createElement("th");
    th.title = "hover"
    th.style.background = "#f0f8ff";
    th.textContent = pkg;

    th.addEventListener("mouseover", () =&gt; th.style.background = "#d0e8ff");
    th.addEventListener("mouseout", () =&gt; th.style.background = "#f0f8ff");

    th.addEventListener("click", () =&gt; {
        localStorage.setItem("orgmetricsRepo", pkg);
        th.style.background="#a0f8ff";
        window.location.href="../mrcieu.r-universe.dev/repo.html";
    });

    return th;
}
repo_src = {
    return transpose(repo_src_in).map(row =&gt; ({
        ...row,
    }));
}
json_data = FileAttachment("results-json-data.json").json();
maintainer_pkgs = json_data['maintainer_pkgs'];
contributor_pkgs = json_data['contributor_pkgs'];
comaintainers = json_data['comaintainers'];
maintainers = Object.keys(maintainer_pkgs);
all_logins = [...new Set([...Object.keys(maintainer_pkgs), ...Object.keys(contributor_pkgs)])].sort();
searchParams = new URLSearchParams(window.location.search);
setInitialMaintainer = function(searchParams, maintainers) {
    var initialMaintainer = searchParams.get('ctb');
    if (initialMaintainer) {
        localStorage.setItem("orgmetricsMaintainer", initialMaintainer);
    } else {
        initialMaintainer = localStorage.getItem("orgmetricsMaintainer");
    }

    if (!initialMaintainer) {
        initialMaintainer = maintainers [Math.floor(Math.random() * maintainers.length)];
    }

    return initialMaintainer;
}
maintainerSet = setInitialMaintainer(searchParams, maintainers);

viewof maintainer = Inputs.select(
    all_logins,
    {
        multiple: false,
        value: maintainerSet,
        label: htl.html`&lt;b&gt;Contributor:&lt;/b&gt;`
    }
)
s = localStorage.setItem("orgmetricsMaintainer", maintainer.toString());
maintainer_gh_url =
    htl.html`&lt;a href="https://github.com/${maintainer}" target="_blank"&gt;&lt;i&gt;${maintainer}&lt;/i&gt;&lt;/a&gt;`

updateSearchParams = function(searchParams, key, value) {
    if (value) {
        searchParams.set(key, value);
    }
    return searchParams;
}
searchParamsMaintainer = updateSearchParams(searchParams, 'ctb', maintainer.toString());
url = window.location.pathname;
hash = window.location.hash;
url_new = `${url}?${searchParamsMaintainer.toString()}${hash}`;
tempvar = window.history.replaceState(null, '', url_new);
these_pkgs = maintainer_pkgs[maintainer] || [];
these_ctb_pkgs = contributor_pkgs[maintainer] || [];
these_ctb_pkg_names = these_ctb_pkgs.map(d =&gt; d.package);

these_cos = comaintainers[maintainer] || null
these_cos_list = these_cos ?
these_cos.map(i =&gt; htl.html`
&lt;div onclick=${() =&gt; localStorage.setItem('orgmetricsMaintainer', i)}&gt;
&lt;li&gt;&lt;a href="../mrcieu.r-universe.dev/contributor.html"&gt;${i}&lt;/a&gt;&lt;/li&gt;
&lt;/div&gt;`) : htl.html`&lt;li&gt;No co-maintainers&lt;/li&gt;`;

Maintained Repositories
This is a sub-set of the main table on the Organization page, showing repository metrics aggregated across the four categories described there. Values are shown only for repositories where  is listed as a maintainer or author in the package DESCRIPTION file, and are scaled between 0 and 1 based on the distribution of values across the entire organization, with higher values always better than lower values.


metricsGroupedTable = {
    return transpose(metrics_table_in).map(row =&gt; ({
        ...row,
    }));
}
metricsTable = these_pkgs.length &gt; 0
    ? metricsGroupedTable.filter(i =&gt; these_pkgs.includes(i.package))
    : [];
















Inputs.table(metricsTable, {
    width: {
        package: 100,
        total: 200,
        development: 200,
        issues: 200,
        popularity: 200,
        meta: 200,
    },
    format: {
        package: d =&gt; pkgfmt(d),
        development: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.development)),
        issues: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.issues)),
        popularity: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.popularity)),
        meta: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.meta)),
        total: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.total)),
    },
    header: {
        development: tooltip("Development", "Code development and maintenance metrics"),
        issues: tooltip("Issues", "GitHub issues and pull request activity"),
        popularity: tooltip("Popularity", "Project popularity on CRAN (where applicable) and GitHub"),
        meta: tooltip("Dependencies and releases", ""),
        total: tooltip("Overall", "Average across all four categories of metrics."),
    },
})

Contributor Repositories
Packages to which  has committed but is not listed as a maintainer or author in the package DESCRIPTION file. Commit counts are for this contributor only; metrics describe the package as a whole.


ctbCommitsMax = d3.max(these_ctb_pkgs, d =&gt; d.contributions) || 1;
these_ctb_pkgs.length &gt; 0
    ? Inputs.table(these_ctb_pkgs, {
        columns: ["package", "contributions"],
        header: {
            package: "Package",
            contributions: tooltip("Commits", "Number of commits by this contributor to the package")
        },
        format: {
            package: d =&gt; pkgfmt(d),
            contributions: sparkbar(ctbCommitsMax)
        }
    })
    : htl.html`&lt;p&gt;&lt;i&gt;No contributor-only repositories found.&lt;/i&gt;&lt;/p&gt;`
















ctbMetricsTable = these_ctb_pkg_names.length &gt; 0
    ? metricsGroupedTable.filter(i =&gt; these_ctb_pkg_names.includes(i.package))
    : [];
ctbMetricsTable.length &gt; 0
    ? Inputs.table(ctbMetricsTable, {
        width: {
            package: 100,
            total: 200,
            development: 200,
            issues: 200,
            popularity: 200,
            meta: 200,
        },
        format: {
            package: d =&gt; pkgfmt(d),
            development: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.development)),
            issues: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.issues)),
            popularity: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.popularity)),
            meta: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.meta)),
            total: sparkbar(d3.max(metricsGroupedTable, d =&gt; d.total)),
        },
        header: {
            development: tooltip("Development", "Code development and maintenance metrics"),
            issues: tooltip("Issues", "GitHub issues and pull request activity"),
            popularity: tooltip("Popularity", "Project popularity on CRAN (where applicable) and GitHub"),
            meta: tooltip("Dependencies and releases", ""),
            total: tooltip("Overall", "Average across all four categories of metrics."),
        },
    })
    : htl.html``

Network
The following network diagram can be zoomed, moved, and dragged to dynamically explore how the selected maintainer is related to both packages and other maintainers. Although zooming and moving can be controlled within the diagram itself using either mouse or gestures, gestures may become confused for large, dense diagrams. The sliders immediately below may offer an easier way to control movement.

width = 928;
height = 600;

viewof x0 = {
    let input = Inputs.range([-width, width],
        {
            value: -width / 2,
            step: 10,
            label: "x"
        }
    )
    d3.select(input).select('input[type="number"]').style("display", "none");
    return input;
}

viewof y0 = {
    let input = Inputs.range([-height, height],
        {
            value: -height / 2,
            step: 10,
            label: "y"
        }
    )
    d3.select(input).select('input[type="number"]').style("display", "none");
    return input;
}

viewof strength = {
    let input = Inputs.range([0, 800],
        {
            value: 50,
            step: 10,
            label: "zoom"
        }
    )
    d3.select(input).select('input[type="number"]').style("display", "none");
    return input;
}





































co_pkgs = these_cos ? these_cos.map(i =&gt; maintainer_pkgs[i]).flat() : [];
pkgs_expanded_full = [
    ...these_pkgs,
    ...co_pkgs
];
// Reduce to unique pkgs:
pkgs_expanded = [...new Set(pkgs_expanded_full)];

co_nodes = these_cos ?
    these_cos.map(item =&gt; ({ id: item, group: "Co-maintainer", size: 6 })) : [];
ctb_pkg_nodes = these_ctb_pkg_names
    .filter(item =&gt; !pkgs_expanded.includes(item))
    .map(item =&gt; ({ id: item, group: "Contributed packages", size: 5 }));
nodes = [
    { id: maintainer, group: "Maintainer", size: 10 },
    ...pkgs_expanded.map(item =&gt; ({
        id: item,
        group: these_pkgs.includes(item) ? "packages" : "otherPackages",
        size: these_pkgs.includes(item) ? 8 : 4,
    })),
    ...co_nodes,
    ...ctb_pkg_nodes
];

// edges are mappings from co-maintainers to all packages. First collect list
// of all packages from co-maintainers:
these_co_pkgs = these_cos ? these_cos.reduce((acc, key) =&gt; {
    if (maintainer_pkgs.hasOwnProperty(key)) {
        if (!these_pkgs.includes(key)) {
            acc[key] = maintainer_pkgs[key];
        }
    }
    return acc;
}, {}) : [];
// Then flatten that to (source, target) pairs of (maintainer, package):
these_co_pkgs_flat = Object.entries(these_co_pkgs).flatMap(([source, targets]) =&gt;
    targets.map(target =&gt; ({ source, target }))
);
links = [
    ...these_pkgs.map(item =&gt; ({
        source: maintainer, target: item, value: 4
    })),
    ...these_co_pkgs_flat.map(item =&gt; ({
        source: item.source, target: item.target, value: 2
    })),
    ...these_ctb_pkg_names
        .filter(item =&gt; !pkgs_expanded.includes(item))
        .map(item =&gt; ({ source: maintainer, target: item, value: 1 }))
];




































































types = Array.from(new Set(nodes.map(d =&gt; d.group))).sort((a, b) =&gt; {
    if (a === "otherPackages") return 1;
    if (b === "otherPackages") return -1;
    return 0;
});

viewof selectedGroups = Inputs.checkbox(
    types,
    {
        label: "Filter by group:",
        value: types.filter(t =&gt; t !== "otherPackages")
    }
)

filteredNodes = nodes.filter(node =&gt; selectedGroups.includes(node.group) || selectedGroups.length === 0);

nodeIds = new Set(filteredNodes.map(node =&gt; node.id));
filteredLinks = links.filter(link =&gt;
    nodeIds.has(typeof link.source === 'object' ? link.source.id : link.source) &&
    nodeIds.has(typeof link.target === 'object' ? link.target.id : link.target)
);





































import {Swatches} from "@d3/color-legend"
Swatches(chart.scales.color)
















chart = {

    const width = 928;
    const height = 600;

    const color = d3.scaleOrdinal(types, d3.schemeCategory10);

    const simulation = d3.forceSimulation(filteredNodes)
        .force("link", d3.forceLink(filteredLinks).id(d =&gt; d.id))
        .force("charge", d3.forceManyBody().strength(-strength))
        .force("x", d3.forceX())
        .force("y", d3.forceY());

    const svg = d3.create("svg")
        .attr("viewBox", [x0, y0, width, height])
        .attr("width", width)
        .attr("height", height)
        .attr("style", "max-width: 100%; height: auto; font: 14px sans-serif;");

    const zoom = d3.zoom()
        .scaleExtent([0.1, 10])
        .on("zoom", (event) =&gt; {
            // Update the viewBox for panning
            const transform = event.transform;
            const newX0 = -transform.x;
            const newY0 = -transform.y;
            const newWidth = width / transform.k;
            const newHeight = height / transform.k;

            svg.attr("viewBox", [newX0, newY0, newWidth, newHeight]);

            // update observable variables:
            if (viewof x0) viewof x0.value = newX0;
            if (viewof y0) viewof y0.value = newY0;

            // Update strength based on zoom level (inverse relationship)
            const newStrength = Math.max(10, Math.min(800, strength * transform.k));
            if (viewof strength) viewof strength.value = newStrength;

            // Update simulation with new strength
            simulation.force("charge", d3.forceManyBody().strength(-newStrength));
            simulation.alpha(0.3).restart();
        });

    // apply zoom behaviour to svg:
    svg.call(zoom);

    // create container for all context that will be transformed:
    const container = svg.append("g");

    const link = container.append("g")
        .attr("fill", "none")
        .attr("stroke-width", 1.5)
        .selectAll("path")
        .data(filteredLinks)
        .join("path")
            .attr("stroke", "gray")
            .attr("stroke-width", d =&gt; d.value);

    const node = container.append("g")
        .selectAll("g")
        .data(filteredNodes)
        .join("g")
            .call(drag(simulation));

    node.append("circle")
        .attr("stroke", "white")
        .attr("stroke-width", 1.5)
        .data(filteredNodes)
        .join("circle")
            .attr("fill", d =&gt; color(d.group))
            .attr("r", d =&gt; d.size);

    node.append("text")
        .attr("x", 8)
        .attr("y", "0.31em")
        .text(d =&gt; d.id)
        .html(d =&gt; d.group === "Co-maintainer" ?
            `&lt;a href="../mrcieu.r-universe.dev/contributor.html"
                onclick="localStorage.setItem('orgmetricsMaintainer', '${d.id}')"&gt;${d.id}&lt;/a&gt;` :
            ((d.group === "packages" || d.group === "otherPackages" || d.group === "Contributed packages") ?
                `&lt;a href="../mrcieu.r-universe.dev/repo.html"
                    onclick="localStorage.setItem('orgmetricsRepo', '${d.id}')"&gt;${d.id}&lt;/a&gt;` :
            d.id))
        .clone(true).lower()
            .attr("fill", "none")
            .attr("stroke", "white")
            .attr("stroke-width", 3);

    simulation.on("tick", () =&gt; {
        link.attr("d", linkArc);
        node.attr("transform", d =&gt; `translate(${d.x},${d.y})`);
    });

    // set initial zoom transform to match current x0, y0:
    const initialTransform = d3.zoomIdentity.translate(-x0, -y0);
    svg.call(zoom.transform, initialTransform);

    invalidation.then(() =&gt; simulation.stop());

    return Object.assign(svg.node(), {scales: {color}});
}







function linkArc(d) {
    const r = Math.hypot(d.target.x - d.source.x, d.target.y - d.source.y);
    return `
    M${d.source.x},${d.source.y}
    A${r},${r} 0 0,1 ${d.target.x},${d.target.y}
    `;
}







drag = simulation =&gt; {

    function dragstarted(event, d) {
        if (!event.active) simulation.alphaTarget(0.3).restart();
        d.fx = d.x;
        d.fy = d.y;

        // prevent zoom behaviour during drag:
        event.sourceEvent.stopPropagation();
    }

    function dragged(event, d) {
        d.fx = event.x;
        d.fy = event.y;
    }

    function dragended(event, d) {
        if (!event.active) simulation.alphaTarget(0);
        d.fx = null;
        d.fy = null;
    }

    return d3.drag()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended);
}

Package Network
This graph shows dependencies between all packages which use any other organization package.

Nodes show individual packages, with circles for each package scaled by total numbers of dependent packages; that is, numbers of other packages which depend on that package.
Edges connect dependent packages, with thicknesses scaled by total numbers of function calls by all dependent packages.

The diagram can be zoomed, moved, and dragged to dynamically explore how packages inter-related. The initial “Repository” control highlights the selected repository in red.

pkg_nodes = {
    return transpose(nodes_in).map(row =&gt; ({
        ...row,
        colour: "blue"
    }));
}
pkg_edges = {
    return transpose(edges_in).map(row =&gt; ({
        ...row,
    }));
}




















nodeIds = pkg_nodes.map(item =&gt; item.id);
initialId = localStorage.getItem("orgmetricsRepo") ||
        nodeIds [Math.floor(Math.random() * nodeIds.length)];
viewof selectedNode = Inputs.select(
    nodeIds,
    {
        multiple: false,
        value: initialId,
        label: htl.html`&lt;b&gt;Repository:&lt;/b&gt;`
    }
)
s = localStorage.setItem("orgmetricsRepo", selectedNode.toString());

































width = 928;
height = 600;

chart = {

    const x0 = -width / 2;
    const y0 = -height / 2;
    const strength = 50;

    const types = Array.from(new Set(pkg_nodes.map(d =&gt; d.group)));

    const color = d3.scaleOrdinal(types, d3.schemeCategory10);

    const simulation = d3.forceSimulation(pkg_nodes)
        .force("link", d3.forceLink(pkg_edges).id(d =&gt; d.id))
        .force("charge", d3.forceManyBody().strength(-strength))
        .force("x", d3.forceX())
        .force("y", d3.forceY());

    const svg = d3.create("svg")
        .attr("viewBox", [x0, y0, width, height])
        .attr("width", width)
        .attr("height", height)
        .attr("style", "max-width: 100%; height: auto; font: 14px sans-serif;");

    const zoom = d3.zoom()
        .scaleExtent([0.1, 10])
        .on("zoom", (event) =&gt; {
            // Update the viewBox for panning
            const transform = event.transform;
            const newX0 = -transform.x;
            const newY0 = -transform.y;
            const newWidth = width / transform.k;
            const newHeight = height / transform.k;

            svg.attr("viewBox", [newX0, newY0, newWidth, newHeight]);

            // Update strength based on zoom level (inverse relationship)
            const newStrength = Math.max(10, Math.min(800, strength * transform.k));

            // Update simulation with new strength
            simulation.force("charge", d3.forceManyBody().strength(-newStrength));
            simulation.alpha(0.3).restart();
        });

    // apply zoom behaviour to svg:
    svg.call(zoom);

    // create container for all context that will be transformed:
    const container = svg.append("g");

    const link = container.append("g")
        .attr("fill", "none")
        .attr("stroke-width", 1.5)
        .selectAll("path")
        .data(pkg_edges)
        .enter().append("path")
            .attr("stroke", "gray")
            .attr("stroke-width", d =&gt; 5 * Math.log10(d.value));

    const node = container.append("g")
        .selectAll("g")
        .data(pkg_nodes)
        .join("g")
            .call(drag(simulation));

    node.append("circle")
        .attr("stroke", "white")
        .attr("stroke-width", 1.5)
        .data(pkg_nodes)
        .join("circle")
            .attr("fill", d =&gt; color(d.group))
            .attr("r", d =&gt; 5 * Math.log10(d.size));

    node.append("text")
        .attr("x", 8)
        .attr("y", "0.31em")
        .style("font-size", "14px")
        .attr("fill", d =&gt; (d.id === selectedNode ? "red" : ""))
        .text(d =&gt; d.id)
        .html(d =&gt;
            `&lt;a href="../mrcieu.r-universe.dev/repo.html"
                onclick="localStorage.setItem('orgmetricsRepo', '${d.id}')"&gt;${d.id}
            &lt;/a&gt;`)
        .clone(true).lower()
            .attr("fill", "none")
            .attr("stroke", "white")
            .attr("stroke-width", 3);

    simulation.on("tick", () =&gt; {
        link.attr("d", linkArc);
        node.attr("transform", d =&gt; `translate(${d.x},${d.y})`);
    });

    // set initial zoom transform to match current x0, y0:
    const initialTransform = d3.zoomIdentity.translate(-x0, -y0);
    svg.call(zoom.transform, initialTransform);

    invalidation.then(() =&gt; simulation.stop());

    return Object.assign(svg.node(), {scales: {color}});
}























function linkArc(d) {
    const r = Math.hypot(d.target.x - d.source.x, d.target.y - d.source.y);
    return `
    M${d.source.x},${d.source.y}
    A${r},${r} 0 0,1 ${d.target.x},${d.target.y}
    `;
}







drag = simulation =&gt; {

    function dragstarted(event, d) {
        if (!event.active) simulation.alphaTarget(0.3).restart();
        d.fx = d.x;
        d.fy = d.y;

        // prevent zoom behaviour during drag:
        event.sourceEvent.stopPropagation();
    }

    function dragged(event, d) {
        d.fx = event.x;
        d.fy = event.y;
    }

    function dragended(event, d) {
        if (!event.active) simulation.alphaTarget(0);
        d.fx = null;
        d.fy = null;
    }

    return d3.drag()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended);
}









